#requires -Version 5.1
<# Created by Dewald Pretorius #>
param([string]$OutputPath)
if(-not $OutputPath){$OutputPath="$([Environment]::GetFolderPath('Desktop'))\Edge_Profile_Sync_Reports"};New-Item $OutputPath -ItemType Directory -Force|Out-Null
$profiles=Get-ChildItem "$env:LOCALAPPDATA\Microsoft\Edge\User Data" -Directory -ErrorAction SilentlyContinue|Where-Object Name -match 'Default|Profile'|Select-Object Name,FullName,LastWriteTime;$targets='edge.microsoft.com','login.microsoftonline.com','graph.microsoft.com';$net=foreach($t in $targets){[pscustomobject]@{Target=$t;HTTPS443=(Test-NetConnection $t -Port 443 -InformationLevel Quiet -WarningAction SilentlyContinue)}}
@('MICROSOFT EDGE PROFILE AND SYNC TROUBLESHOOTER','Created by Dewald Pretorius',"Generated: $(Get-Date)",'Profiles:',($profiles|Format-Table -AutoSize|Out-String -Width 220),($net|Format-Table -AutoSize|Out-String -Width 220),'Guidance: verify profile identity, sync consent, policy restrictions, passphrase state, profile corruption, extension conflicts, and service connectivity.')|Set-Content (Join-Path $OutputPath 'Report.txt') -Encoding UTF8